// Load script setelah DOM berhasil dimuat
$(function () {
    
    // Inisialisasi data tabel billboard-list
    TableHelper.init("#tableBillboardList", {
        ajax: window.routes.dataTable, // Mengambil endpoint url data tabel dari global window variabel
        order: [[1, "asc"]],
        filters: [4, 7], // filter untuk Status & Aktif saja
        buttons: [
            {
                text: "Add",
                attr: {
                    "data-target": "#modalAddBillboard",
                    "data-toggle": "modal",
                },
            },
            { text: "Excel" },
        ],
        columnDefs: [
            { responsivePriority: 1, targets: [1, 4, 5, 7, 3, 8, 9, 0, 11] }, // kolom penting utama
            { responsivePriority: 2, targets: [6] }, // kolom sekunder
            { targets: [10, 12, 13, 14, 15, 16], className: "none" }, // sembunyikan detail
        ],
        columns: [
            {
                data: "id",
                title: "ID",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "judul",
                title: "Judul",
                className: "dt-head-center",
                orderable: true,
            },
            {
                data: "area",
                title: "Area",
                className: "dt-head-center",
                orderable: true,
            },
            {
                data: "lokasi",
                title: "Lokasi",
                className: "dt-head-center",
                orderable: false,
            },
            {
                data: "status",
                title: "Status",
                className: "dt-head-center dt-body-center",
                orderable: true,
                render: {
                    _: (val) => (val == 1 ? "Tersedia" : "Tersewa"),
                    display: (val) =>
                        val == 1
                            ? '<span class="lencana bg-success">Tersedia</span>'
                            : '<span class="lencana bg-secondary">Tersewa</span>',
                },
            },
            {
                data: "aktif",
                title: "Aktif",
                className: "dt-head-center dt-body-center col-boolean",
                orderable: true,
                render: {
                    _: (val) => (val == 1 ? "Aktif" : "Non Aktif"),
                    display: (val) =>
                        val == 1
                            ? '<span class="lencana bg-primary">Aktif</span>'
                            : '<span class="lencana bg-danger">Non Aktif</span>',
                },
            },
            {
                data: "keterangan",
                title: "Keterangan",
                className: "dt-head-center",
                orderable: true,
            },
            {
                data: "jenis",
                title: "Jenis",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "ukuran",
                title: "Ukuran (m)",
                className: "dt-head-center dt-body-center",
                orderable: false,
            },
            {
                data: "unit",
                title: "Unit",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "koordinat",
                title: "Koordinat",
                className: "dt-head-center dt-body-center",
                orderable: false,
            },
            {
                data: "gambar",
                title: "Gambar",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: {
                    _: (gambar) => gambar,
                    display: (gambar) =>
                        gambar
                            ? `<figure class="figure mb-0">
                                    <img src="/storage/billboards/${gambar}" 
                                        alt="Gambar Billboard" 
                                        class="figure-img img-fluid img-thumbnail rounded" 
                                        style="width: 80px; height: auto; object-fit: cover;" />
                                    <figcaption class="figure-caption text-center small text-muted">
                                        Preview
                                    </figcaption>
                                </figure>`
                            : `<span class="text-muted"></span>`,
                },
            },
            {
                data: "created_at",
                title: "Dibuat",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "updated_at",
                title: "Diubah",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "admin_buat",
                title: "Pembuat",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "admin_ubah",
                title: "Pengubah",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "aksi",
                title: "Aksi",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: (data, type) => (type === "display" ? data : ""),
            },
        ],
    });

    // Trigger modal upload gambar
    $(document).on(
        "click",
        '#tableBillboardList button[data-target="#modalUploadGambarBillboard"]',
        function () {
            let id = $(this).data("id");
            let $form = $("#formUploadGambarBillboard");

            // Mendefinisikan endpoint route dari global window untuk upload gambar billboard
            $form.attr("action", window.routes.uploadGambar.replace(":id", id));
        }
    )
});



